# --- Token store (in production, use a proper secret store / DB) ---
class TokenStore:
    """Simple in-memory token store for demonstration."""
    
    def __init__(self):
        self._tokens = {}  # token -> {"user": ..., "roles": [...], "expires": ...}
    
    def add_token(self, token: str, user: str, roles: list, ttl_seconds: int = 3600):
        self._tokens[token] = {
            "user": user,
            "roles": roles,
            "expires": time.time() + ttl_seconds,
        }
    
    def validate_token(self, token: str):
        """Returns user info dict if valid, None otherwise."""
        info = self._tokens.get(token)
        if info is None:
            return None
        if time.time() > info["expires"]:
            del self._tokens[token]
            return None
        return info
    
    def generate_token(self, user: str, roles: list, ttl_seconds: int = 3600) -> str:
        token = secrets.token_urlsafe(32)
        self.add_token(token, user, roles, ttl_seconds)
        return token


# Global token store instance
