# --- Rate limiter for auth failures ---
class AuthRateLimiter:
    """Rate limiter to prevent brute-force token guessing."""
    
    def __init__(self, max_failures: int = 10, window_seconds: int = 60):
        self._failures = defaultdict(list)  # peer -> [timestamps]
        self._max_failures = max_failures
        self._window_seconds = window_seconds
    
    def record_failure(self, peer: str):
        now = time.time()
        self._failures[peer].append(now)
        # Prune old entries
        cutoff = now - self._window_seconds
        self._failures[peer] = [t for t in self._failures[peer] if t > cutoff]
    
    def is_rate_limited(self, peer: str) -> bool:
        now = time.time()
        cutoff = now - self._window_seconds
        self._failures[peer] = [t for t in self._failures[peer] if t > cutoff]
        return len(self._failures[peer]) >= self._max_failures


rate_limiter = AuthRateLimiter()


