# Methods requiring specific roles (admin methods require admin role)
ROLE_REQUIREMENTS = {
    "/myservice.MyService/AdminShutdown": ["admin"],
    "/myservice.MyService/AdminReloadConfig": ["admin"],
    "/myservice.MyService/AdminListUsers": ["admin"],
    "/myservice.MyService/AdminRevokeToken": ["admin"],
    "/myservice.MyService/AdminGetAuditLog": ["admin"],
}


def is_public_method(method_name: str) -> bool:
    """Check if a method is publicly accessible without authentication."""
    if method_name in PUBLIC_METHODS:
        return True
    for prefix in PUBLIC_METHOD_PREFIXES:
        if method_name.startswith(prefix):
            return True
    return False


def get_required_roles(method_name: str) -> list:
    """Get roles required for a specific method. Empty list means any authenticated user."""
    return ROLE_REQUIREMENTS.get(method_name, [])


# --- Interceptors ---

class AuthenticationInterceptor(ServerInterceptor):
    """
    Intercepts RPCs to validate authentication tokens.
    
    Public endpoints (health, metrics) skip auth for monitoring compatibility.
    All other endpoints, INCLUDING admin endpoints, require valid authentication.
    Admin endpoints additionally require the 'admin' role.
    """
    
    def __init__(self, token_store: TokenStore):
        self._token_store = token_store
    
    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method
        
        # Allow public methods without authentication
        if is_public_method(method):
            logger.debug(f"Public method accessed: {method}")
            return continuation(handler_call_details)
        
        # Check rate limiting by peer
        peer = self._get_peer(handler_call_details)
        if rate_limiter.is_rate_limited(peer):
            logger.warning(f"Rate limited peer {peer} attempted access to {method}")
            return self._unauthenticated_handler("Too many authentication failures. Try again later.")
        
        # Extract and validate token
        metadata = dict(handler_call_details.invocation_metadata or [])
        auth_header = metadata.get("authorization", "")
        
        if not auth_header:
            logger.warning(f"Missing auth token for method: {method} from peer: {peer}")
            rate_limiter.record_failure(peer)
            return self._unauthenticated_handler("Missing authorization metadata")
        
        # Support "Bearer <token>" format
        token = auth_header
        if auth_header.lower().startswith("bearer "):
            token = auth_header[7:]
        
        user_info = self._token_store.validate_token(token)
        if user_info is None:
            logger.warning(f"Invalid/expired token for method: {method} from peer: {peer}")
            rate_limiter.record_failure(peer)
            return self._unauthenticated_handler("Invalid or expired token")
        
        # Check role-based authorization
        required_roles = get_required_roles(method)
        if required_roles:
            user_roles = set(user_info.get("roles", []))
            if not any(role in user_roles for role in required_roles):
                logger.warning(
                    f"User '{user_info['user']}' lacks required roles {required_roles} "
                    f"for method: {method}"
                )
                return self._permission_denied_handler(
                    f"Requires one of roles: {required_roles}"
                )
        
        logger.info(f"Authenticated user '{user_info['user']}' accessing {method}")
        return continuation(handler_call_details)
    
    def _get_peer(self, handler_call_details):
        """Extract peer information for rate limiting."""
        metadata = dict(handler_call_details.invocation_metadata or [])
        return metadata.get("peer", "unknown")
    
    def _unauthenticated_handler(self, message: str):
        """Return a handler that sends UNAUTHENTICATED status."""
        def handle(request, context):
            context.abort(grpc.StatusCode.UNAUTHENTICATED, message)
        
        return grpc.unary_unary_rpc_method_handler(handle)
    
    def _permission_denied_handler(self, message: str):
        """Return a handler that sends PERMISSION_DENIED status."""
        def handle(request, context):
            context.abort(grpc.StatusCode.PERMISSION_DENIED, message)
        
        return grpc.unary_unary_rpc_method_handler(handle)


class AuditLoggingInterceptor(ServerInterceptor):
    """Logs all RPC calls for audit purposes."""
    
    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method
        metadata = dict(handler_call_details.invocation_metadata or [])
        
        # Log admin access with higher severity
        if "/Admin" in method or "/admin" in method:
            logger.warning(f"AUDIT: Admin method accessed: {method}")
        else:
            logger.info(f"AUDIT: Method accessed: {method}")
        
        return continuation(handler_call_details)


